/**
 * @param {number[]} digitSum
 * @return {number}
 */
function solve(digitSum) {
    const MOD = 10**9 + 7;
    const MAX_VAL = 5000;

    /**
     * Calculates the sum of digits of a number.
     * @param {number} n
     * @returns {number}
     */
    const getDigitSum = (n) => {
        let sum = 0;
        n = Math.abs(n);
        while (n > 0) {
            sum += n % 10;
            n = Math.floor(n / 10);
        }
        return sum;
    };

    /**
     * Precompute a map for each required digit sum:
     * map[s] = list of all numbers x such that 0 <= x <= 5000 and getDigitSum(x) == s.
     * The list must be sorted in ascending order.
     * @param {number[]} requiredSums - The unique digit sums we need to consider.
     * @returns {Map<number, number[]>}
     */
    const precomputeNumbers = (requiredSums) => {
        const numberMap = new Map();
        for (const s of requiredSums) {
            numberMap.set(s, []);
        }

        for (let x = 0; x <= MAX_VAL; x++) {
            const s = getDigitSum(x);
            if (numberMap.has(s)) {
                numberMap.get(s).push(x);
            }
        }
        return numberMap;
    };

    // 1. Identify all unique required digit sums
    const uniqueDigitSums = Array.from(new Set(digitSum));

    // 2. Precompute the lists of valid numbers for each required sum
    const numberMap = precomputeNumbers(uniqueDigitSums);

    // Check if any required sum has no corresponding numbers in [0, 5000]
    for (const s of digitSum) {
        if (!numberMap.has(s) || numberMap.get(s).length === 0) {
            return 0;
        }
    }

    const N = digitSum.length;

    // DP state: dp[i][prev_val] is the number of valid prefixes of length i+1 ending with a value >= prev_val.
    // Since prev_val can be up to 5000, using the actual value in the DP state is too slow (O(N * 5001)).
    // We must use the indices into the precomputed sorted lists.

    // Let V[i] be the sorted list of numbers corresponding to digitSum[i].
    const V = digitSum.map(s => numberMap.get(s));

    // dp[i][j]: The number of valid sequences for the first i+1 elements (0 to i) 
    // such that the (i)-th element (arr[i]) is exactly V[i][j].
    // i: index in digitSum (0 to N-1)
    // j: index in V[i] (0 to V[i].length - 1)

    // We use two arrays for space optimization (current and previous row).
    // dp_prev[j]: count ending with V[i-1][j]
    // dp_curr[j]: count ending with V[i][j]

    let dp_prev;
    if (N === 0) return 0;

    // Base case: i = 0
    const L0 = V[0].length;
    dp_prev = new Array(L0).fill(1); // Any number for arr[0] starts a valid sequence of length 1

    // Iterate from i = 1 to N-1
    for (let i = 1; i < N; i++) {
        const Vi = V[i];
        const Li = Vi.length;
        const L_prev = V[i - 1].length;
        const dp_curr = new Array(Li).fill(0);

        // Optimization: Precompute prefix sums for dp_prev
        // prefix_sum_prev[j] = sum(dp_prev[0]...dp_prev[j])
        const prefix_sum_prev = new Array(L_prev).fill(0);
        prefix_sum_prev[0] = dp_prev[0];
        for (let j = 1; j < L_prev; j++) {
            prefix_sum_prev[j] = (prefix_sum_prev[j - 1] + dp_prev[j]) % MOD;
        }

        // For each element arr[i] = Vi[j]
        for (let j = 0; j < Li; j++) {
            const current_val = Vi[j];
            let count = 0;

            // We need to sum dp_prev[k] for all k such that V[i-1][k] <= current_val

            // Binary search (or two pointers since Vi and V[i-1] are sorted) to find the largest index k_max
            // such that V[i-1][k_max] <= current_val.

            // Since V[i-1] is sorted, we find the count of elements in V[i-1] that are <= current_val.

            let low = 0;
            let high = L_prev - 1;
            let k_max = -1;

            while (low <= high) {
                const mid = Math.floor((low + high) / 2);
                if (V[i-1][mid] <= current_val) {
                    k_max = mid;
                    low = mid + 1;
                } else {
                    high = mid - 1;
                }
            }

            // If k_max is -1, no previous element is <= current_val, so count is 0.
            if (k_max >= 0) {
                // The required sum is dp_prev[0] + ... + dp_prev[k_max]
                count = prefix_sum_prev[k_max];
            }

            dp_curr[j] = count;
        }

        dp_prev = dp_curr;
    }

    // Final result: sum of all elements in the last DP array (dp_prev)
    let totalCount = 0;
    for (const count of dp_prev) {
        totalCount = (totalCount + count) % MOD;
    }

    return totalCount;
}

